pub fn usage(bin: &str) -> String {
    format!(
        "Usage:\n  {bin} --management-interface <iface> --data-plane-interface <iface|pci|mac> --dns-target-ip <ipv4> --dns-upstream <ip:port> [--data-plane-mode tun|tap|dpdk] [--idle-timeout-secs <secs>] [--dns-allowlist-idle-secs <secs>] [--dns-allowlist-gc-interval-secs <secs>] [--default-policy allow|deny] [--dhcp-timeout-secs <secs>] [--dhcp-retry-max <count>] [--dhcp-lease-min-secs <secs>] [--internal-cidr <cidr>] [--snat none|auto|<ipv4>] [--encap none|vxlan|geneve] [--encap-vni <id>] [--encap-udp-port <port>] [--encap-vni-internal <id>] [--encap-vni-external <id>] [--encap-udp-port-internal <port>] [--encap-udp-port-external <port>] [--encap-mtu <bytes>]\n  {bin} [cluster flags]\n  {bin} auth <command>\n  {bin} sysdump [--output <path>]\n\nFlags:\n  --management-interface <iface>\n  --data-plane-interface <iface|pci|mac> (dpdk accepts pci:0000:00:00.0 or mac:aa:bb:cc:dd:ee:ff)\n  --dns-target-ip <ipv4> (repeatable)\n  --dns-target-ips <csv IPv4 list>\n  --dns-upstream <ip:port> (repeatable)\n  --dns-upstreams <csv ip:port list>\n  --data-plane-mode tun|tap|dpdk (default: tun)\n  --idle-timeout-secs <secs> (default: 300)\n  --dns-allowlist-idle-secs <secs> (default: idle-timeout + 120)\n  --dns-allowlist-gc-interval-secs <secs> (default: 30)\n  --default-policy allow|deny (default: deny)\n  --dhcp-timeout-secs <secs> (default: 5)\n  --dhcp-retry-max <count> (default: 5)\n  --dhcp-lease-min-secs <secs> (default: 60)\n  --internal-cidr <cidr> (overrides DHCP-derived internal network)\n  --snat none|auto|<ipv4>\n  --encap none|vxlan|geneve (default: none)\n  --encap-vni <id>\n  --encap-vni-internal <id>\n  --encap-vni-external <id>\n  --encap-udp-port <port> (default: 10800 for vxlan, 6081 for geneve)\n  --encap-udp-port-internal <port> (default: 10800 when --encap-vni-internal is set)\n  --encap-udp-port-external <port> (default: 10801 when --encap-vni-external is set)\n  --encap-mtu <bytes> (default: 1500)\n  --http-bind <ip:port> (default: <management-ip>:8443)\n  --http-advertise <ip:port> (default: http-bind)\n  --http-external-url <https://host[:port]> (default: https://http-advertise)\n  --http-tls-dir <path> (default: /var/lib/neuwerk/http-tls)\n  --http-cert-path <path>\n  --http-key-path <path>\n  --http-ca-path <path>\n  --http-tls-san <comma-separated>\n  --metrics-bind <ip:port> (default: <management-ip>:8080)\n  --cloud-provider azure|aws|gcp|none (default: none)\n  --integration azure-vmss|aws-asg|gcp-mig|none (default: none)\n  --integration-route-name <name> (default: neuwerk-default)\n  --integration-drain-timeout-secs <secs> (default: 300)\n  --integration-reconcile-interval-secs <secs> (default: 15)\n  --integration-cluster-name <name> (default: neuwerk)\n  --azure-subscription-id <id>\n  --azure-resource-group <name>\n  --azure-vmss-name <name>\n  --aws-region <region>\n  --aws-vpc-id <id>\n  --aws-asg-name <name>\n  --gcp-project <id>\n  --gcp-region <region>\n  --gcp-ig-name <name>\n  --cluster-migrate-from-local\n  --cluster-migrate-force\n  --cluster-migrate-verify\n  --cluster-bind <ip:port>\n  --cluster-join-bind <ip:port> (default: cluster-bind + 1)\n  --cluster-advertise <ip:port> (default: cluster-bind)\n  --join <ip:port>\n  --cluster-data-dir <path> (default: /var/lib/neuwerk/cluster)\n  --node-id-path <path> (default: /var/lib/neuwerk/node_id)\n  --bootstrap-token-path <path> (default: /var/lib/neuwerk/bootstrap-token)\n  -h, --help\n\nAuth Commands:\n  {bin} auth key rotate --cluster-addr <ip:port> [--cluster-tls-dir <path>]\n  {bin} auth key rotate --http-tls-dir <path>\n  {bin} auth key list --cluster-addr <ip:port> [--cluster-tls-dir <path>]\n  {bin} auth key list --http-tls-dir <path>\n  {bin} auth key retire <kid> --cluster-addr <ip:port> [--cluster-tls-dir <path>]\n  {bin} auth key retire <kid> --http-tls-dir <path>\n  {bin} auth token mint --sub <id> [--ttl <dur>] [--kid <kid>] [--roles <csv>] --cluster-addr <ip:port> [--cluster-tls-dir <path>]\n  {bin} auth token mint --sub <id> [--ttl <dur>] [--kid <kid>] [--roles <csv>] --http-tls-dir <path>\n"
    )
}
